import React, { useState, useEffect } from 'react';
import { getSeances, addSeance } from '../services/api';

function Seances() {
  const [seances, setSeances] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const [formData, setFormData] = useState({
    date: '',
    heure: '',
    capacite: '',
    id_sport: '',
    id_coach: '',
  });

  const fetchSeances = async () => {
    try {
      const res = await getSeances();
      setSeances(res.data || []);
      setLoading(false);
      setError(null);
    } catch (err) {
      console.error('Erreur frontend getSeances:', err);
      setError('Impossible de charger les séances (erreur serveur)');
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSeances();
  }, []);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await addSeance(formData);
      alert(res.data?.message || 'Séance ajoutée avec succès !');
      setFormData({
        date: '',
        heure: '',
        capacite: '',
        id_sport: '',
        id_coach: '',
      });
      fetchSeances(); // Recharger la liste
    } catch (err) {
      console.error('Erreur ajout séance:', err.response?.data || err);
      alert(
        err.response?.data?.error ||
          err.response?.data?.message ||
          'Erreur lors de l’ajout (vérifiez le serveur)'
      );
    }
  };

  if (loading) return <div className="text-center mt-5">Chargement des séances...</div>;

  if (error) return <div className="alert alert-danger text-center mt-5">{error}</div>;

  return (
    <div className="container mt-4">
      <h2 className="mb-4 text-center">Gestion des Séances Sportives</h2>

      {/* Formulaire d'ajout */}
      <div className="card mb-4 shadow">
        <div className="card-header bg-info text-white">
          <h5 className="mb-0">Ajouter une nouvelle séance</h5>
        </div>
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            <div className="row g-3">
              <div className="col-md-3">
                <label className="form-label">Date</label>
                <input
                  type="date"
                  name="date"
                  className="form-control"
                  value={formData.date}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="col-md-3">
                <label className="form-label">Heure</label>
                <input
                  type="time"
                  name="heure"
                  className="form-control"
                  value={formData.heure}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="col-md-2">
                <label className="form-label">Capacité</label>
                <input
                  type="number"
                  name="capacite"
                  min="1"
                  className="form-control"
                  value={formData.capacite}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="col-md-2">
                <label className="form-label">ID Sport</label>
                <input
                  type="number"
                  name="id_sport"
                  min="1"
                  className="form-control"
                  value={formData.id_sport}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="col-md-2">
                <label className="form-label">ID Coach</label>
                <input
                  type="number"
                  name="id_coach"
                  min="1"
                  className="form-control"
                  value={formData.id_coach}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>

            <div className="mt-4 text-end">
              <button type="submit" className="btn btn-info">
                Ajouter la séance
              </button>
            </div>
          </form>
        </div>
      </div>

      {/* Liste des séances */}
      {seances.length === 0 ? (
        <div className="alert alert-info text-center">
          Aucune séance enregistrée pour le moment
        </div>
      ) : (
        <div className="table-responsive">
          <table className="table table-striped table-hover table-bordered">
            <thead className="table-dark">
              <tr>
                <th>ID</th>
                <th>Date</th>
                <th>Heure</th>
                <th>Capacité</th>
                <th>ID Sport</th>
                <th>ID Coach</th>
              </tr>
            </thead>
            <tbody>
              {seances.map((s) => (
                <tr key={s.id_seance}>
                  <td>{s.id_seance}</td>
                  <td>{s.date}</td>
                  <td>{s.heure}</td>
                  <td>{s.capacite}</td>
                  <td>{s.id_sport}</td>
                  <td>{s.id_coach}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default Seances;
